#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAXN 300005

int n;
int edges[MAXN][2];

long long countNiceTriples() {
    long long totalPaths = (long long)n * (n - 1) / 2;
    long long niceTriples = 0;
    // Calculate the number of nice triples of paths
    for (int i = 0; i < n - 1; i++) {
        for (int j = i + 1; j < n - 1; j++) {
            for (int k = j + 1; k < n - 1; k++) {
                // Check if the three paths are nice
                if (areNice(edges[i][0], edges[i][1], edges[j][0], edges[j][1], edges[k][0], edges[k][1])) {
                    niceTriples++;
                }
            }
        }
    }
    return niceTriples % MOD;
}

int areNice(int a, int b, int c, int d, int e, int f) {
    // Check if the three paths are pairwise disjoint or intersecting
    if ((a != c && a != d && b != c && b != d && a != e && a != f && b != e && b != f) ||
        (a == c || a == d || b == c || b == d) && (a == e || a == f || b == e || b == f) && (c == e || c == f || d == e || d == f)) {
        return 1;
    }
    return 0;
}

int main() {
    scanf("%d", &n);
    for (int i = 0; i < n - 1; i++) {
        scanf("%d %d", &edges[i][0], &edges[i][1]);
    }
    printf("%lld\n", countNiceTriples());
    return 0;
}

